#include <stdio.h>
#include "platform.h"

void  __attribute__((used, noinline))  wait_in_wfi() {
  asm volatile("1: wfi\n\t"
               "j 1b" ::: "memory");
}

int global[5];

int main(void) {
  int array[5];
  for (int i = 0; i < 5; ++i) {
    global[i] = i * i;
    array[i] = i * i * i;
    if (i == 3) {
      wait_in_wfi(); // save and resume from here
    }
  }

  for (int i = 0; i < 5; ++i) {
    printf("%d, %d, %d\n", i, array[i], global[i]);
  }

  return 0;
}

